func main() {
    type Task struct {
        Name     string
        Priority int
    }
    tasks := []Task{{"A", 2}, {"B", 1}, {"C", 2}, {"D", 1}}
    sort.SliceStable(tasks, func(i, j int) bool {
        return tasks[i].Priority < tasks[j].Priority
    })
    for _, t := range tasks {
        fmt.Printf("%s(%d) ", t.Name, t.Priority)
    }
    fmt.Println()
    // B(1) D(1) A(2) C(2) — ties preserve original order
}

